/**
 * Panel D — Auto-generated methods text as standalone SVG.
 *
 * Renders formatted text describing analysis parameters,
 * thresholds, and citation information for publication supplements.
 */
import type { ResolvedThresholds } from "@/lib/thresholds";

const FONT = "Arial, Helvetica, sans-serif";
const WIDTH = 800;
const HEIGHT = 400;

/** Format a threshold key into a human-readable label */
function humanizeKey(key: string): string {
  const map: Record<string, string> = {
    muHCutoff: "Hydrophobic moment (uH) cutoff",
    hydroCutoff: "Hydrophobicity cutoff",
    minS4predHelixScore: "Min S4PRED helix score",
    minHelixPercentContent: "Min helix % content",
    minSsPercentContent: "Min secondary structure % content",
    s4predMaxHelixBetaDiff: "S4PRED max helix-beta diff",
    tangoMaxHelixBetaDiff: "TANGO max helix-beta diff",
    minSegmentLength: "Min segment length",
    maxGap: "Max gap",
    aggThreshold: "Aggregation threshold",
    percentOfLengthCutoff: "% of length cutoff",
    minSswResidues: "Min SSW residues",
    sswMaxDifference: "SSW max difference",
    minPredictionPercent: "Min prediction %",
  };
  return map[key] ?? key;
}

function escapeXml(str: string): string {
  return str.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

export interface MethodsPanelOptions {
  /** Reproducibility permalink — full URL encoding the current filtered/threshold state. */
  permalinkURL?: string;
  /** PVL version string (e.g. "0.1.0"). Falls back to "0.1" if not supplied. */
  version?: string;
}

export function generateMethodsSVG(
  thresholds: ResolvedThresholds,
  peptideCount: number,
  options: MethodsPanelOptions = {}
): string {
  const lines: string[] = [];
  let y = 30;
  const lineHeight = 16;
  const sectionGap = 10;

  // Panel label
  lines.push(
    `<text x="12" y="20" font-family="${FONT}" font-size="14" font-weight="bold" fill="#333">D</text>`
  );

  // Title
  y = 50;
  lines.push(
    `<text x="40" y="${y}" font-family="${FONT}" font-size="13" font-weight="bold" fill="#222">Methods</text>`
  );
  y += lineHeight + sectionGap;

  // Description
  // 2026-06-08: fallback bumped from "v0.1" to "v0.3" to match current
  // release. Callers should always pass options.version (via PVL_VERSION
  // from reproducibilityStore); the fallback only fires when the figure
  // pack is generated outside an app context (tests / scripts).
  const versionLabel = options.version ? `v${options.version}` : "v0.3";
  const descLines = [
    `Analysis performed using PVL (Peptide Visual Lab) ${versionLabel}.`,
    `${peptideCount} peptide${peptideCount !== 1 ? "s" : ""} analyzed.`,
    `Date of analysis: ${new Date().toISOString().slice(0, 10)}.`,
  ];
  for (const line of descLines) {
    lines.push(
      `<text x="40" y="${y}" font-family="${FONT}" font-size="10" fill="#333">${escapeXml(line)}</text>`
    );
    y += lineHeight;
  }

  y += sectionGap;

  // Thresholds section
  lines.push(
    `<text x="40" y="${y}" font-family="${FONT}" font-size="11" font-weight="bold" fill="#222">Active Thresholds</text>`
  );
  y += lineHeight;

  // Key thresholds (skip deprecated maxTangoDifference)
  const keys = Object.keys(thresholds).filter((k) => k !== "maxTangoDifference") as Array<
    keyof ResolvedThresholds
  >;

  for (const key of keys) {
    const val = thresholds[key];
    const label = humanizeKey(key);
    lines.push(
      `<text x="50" y="${y}" font-family="${FONT}" font-size="9" fill="#555">${escapeXml(label)}: <tspan font-weight="bold">${val}</tspan></text>`
    );
    y += lineHeight - 2;
  }

  y += sectionGap * 2;

  // Reproducibility permalink (if supplied) — single source of truth for
  // regenerating this figure pack. SVG text doesn't auto-wrap, so very long
  // URLs are truncated visually; the FULL URL still encodes state if the
  // reader inspects the underlying SVG source.
  if (options.permalinkURL) {
    lines.push(
      `<text x="40" y="${y}" font-family="${FONT}" font-size="10" font-weight="bold" fill="#222">Reproduce this figure</text>`
    );
    y += lineHeight - 2;
    const displayURL =
      options.permalinkURL.length > 110
        ? options.permalinkURL.slice(0, 107) + "…"
        : options.permalinkURL;
    lines.push(
      `<text x="40" y="${y}" font-family="${FONT}" font-size="9" fill="#555">${escapeXml(displayURL)}</text>`
    );
    y += lineHeight + sectionGap;
  }

  // Citation
  lines.push(
    `<line x1="40" y1="${y - 6}" x2="${WIDTH - 40}" y2="${y - 6}" stroke="#e0e0e0" stroke-width="0.5"/>`
  );
  lines.push(
    `<text x="40" y="${y + 6}" font-family="${FONT}" font-size="9" fill="#888" font-style="italic">Generated by PVL — https://github.com/saidaz24-meet/peptide_prediction</text>`
  );

  const totalHeight = Math.max(HEIGHT, y + 30);

  return [
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${WIDTH} ${totalHeight}" width="${WIDTH}" height="${totalHeight}">`,
    `<rect width="100%" height="100%" fill="white"/>`,
    ...lines,
    `</svg>`,
  ].join("\n");
}
